<?php namespace App\Domains\Auto\Http\Controllers; use Illuminate\Http\Request; use App\Domains\Auto\Models\Vehicle; class VehicleController { public function index() { return response()->json(Vehicle::all()); } public function store(Request $request) { $vehicle = Vehicle::create($request->all()); return response()->json($vehicle, 201); } public function show(Vehicle $vehicle) { return response()->json($vehicle); } public function update(Request $request, Vehicle $vehicle) { $vehicle->update($request->all()); return response()->json($vehicle); } public function destroy(Vehicle $vehicle) { $vehicle->delete(); return response()->json(null, 204); } }
